INSERT INTO evidence_sources (ref_id,source_type,first_author_last,first_author_first,author_count,author_count_is_complete,is_corporate_primary,pub_year,pub_title,journal_name,doi,url,jurisdiction,language,lang_detected,tier,evidence_type,scope,verification_status,metadata_quality,doi_resolution_outcome,url_resolution_outcome,verified_by_tool,last_verified_at,prior_expectation,search_queries_used,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('REF-00938','journal_article','Tao','Yiyi',5,1,0,2018,'Legibility of floor plans and wayfinding satisfaction of residents in care and attention homes','Australasian Journal on Ageing','10.1111/ajag.12574','https://doi.org/10.1111/ajag.12574','AU','en','en',3,'clinical','lower_control','VERIFIED','COMPLETE','RESOLVED','RESOLVED','scholar_gateway','2026-07-24T16:15:00+00:00','Expected wayfinding-legibility evidence to be lab-based; searched to anchor a real-setting study linking floor-plan legibility to wayfinding satisfaction.','Scholar Gateway: wayfinding spatial cognition environmental legibility architectural design cognitive impairment','Study of floor-plan legibility and wayfinding satisfaction in care homes. Tier 3. Filed to wayfinding-cognitive-science-spatial-design.','2026-07-24T16:15:00+00:00','session_2026-07-24-research-matrix-completion','2026-07-24T16:15:00+00:00','session_2026-07-24-research-matrix-completion');
INSERT INTO evidence_sources (ref_id,source_type,first_author_last,first_author_first,author_count,author_count_is_complete,is_corporate_primary,pub_year,pub_title,journal_name,pmid,jurisdiction,language,lang_detected,tier,evidence_type,scope,verification_status,metadata_quality,verified_by_tool,last_verified_at,prior_expectation,search_queries_used,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('REF-00937','journal_article','Jinno','Hideto',7,1,0,2007,'[Impact of air fresheners and deodorizers on the indoor total volatile organic compounds]','Bulletin of National Institute of Health Sciences (Kokuritsu Iyakuhin Shokuhin Eisei Kenkyujo)','18220049','JP','ja','ja',3,'clinical','lower_control','VERIFIED','PMID-ONLY','pubmed','2026-07-24T16:15:00+00:00','Expected indoor VOC/MCS evidence to be English-dominant; searched Japanese-indexed literature to test whether non-English primary evidence on household-product VOC emissions exists independently.','PubMed: multiple chemical sensitivity indoor air quality volatile organic compounds building environment','JAPANESE-LANGUAGE primary study: VOC/TVOC emission rates of air fresheners/deodorizers (JIS A 1901 chamber); TVOC up to 6900 ug/unit/h; mean indoor increment 170 ug/m3 (~40% of 400 ug/m3 target). Tier 3. Genuine non-English source (not a consensus-mirror). Filed to air-quality-voc-chemical-sensitivity-built-environment.','2026-07-24T16:15:00+00:00','session_2026-07-24-research-matrix-completion','2026-07-24T16:15:00+00:00','session_2026-07-24-research-matrix-completion');
INSERT INTO evidence_sources (ref_id,source_type,is_corporate_primary,author_display,pub_year,pub_title,standard_number,publisher,url,jurisdiction,language,lang_detected,tier,evidence_type,scope,verification_status,metadata_quality,url_resolution_outcome,verified_by_tool,last_verified_at,prior_expectation,search_queries_used,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('REF-00939','code',1,'City of Houston (ICC IRC Appendix AV)',2021,'Residential Code Appendix AV — Visitability','Houston IRC 2021 App. AV','International Code Council / City of Houston','https://up.codes/viewer/houston/irc-2021/chapter/new_AV/visitability','US','en','en',6,'code','national','VERIFIED','COMPLETE-STATUTORY','RESOLVED','web','2026-07-24T16:15:00+00:00','Expected visitability minimums (zero-step entry, 32in doors, main-floor half bath) to be code-adopted somewhere in the US; searched to anchor an adopted municipal visitability code.','WebSearch: visitability zero-step entrance 32 inch clear doorway width residential minimum accessibility','Adopted municipal visitability code: 1 zero-step entrance; 32in clear interior doors; main-floor half bath; thresholds <=3/4in ext /1/2in other; path <=1:20. Tier 6 statutory code (regulatory stratum, weak-band only). Filed to visitability-residential-accessibility-minimum-standards.','2026-07-24T16:15:00+00:00','session_2026-07-24-research-matrix-completion','2026-07-24T16:15:00+00:00','session_2026-07-24-research-matrix-completion');
